230→authRouter.get('/google/callback', async (req: Request, res: Response) => {
231→  const { code, state } = req.query;
232→
233→  if (!code || !state) {
234→    return res.status(400).send('Missing code or state');
235→  }
236→
237→  // Verify state
238→  const [oauthState] = await db
239→    .select()
240→    .from(oauthStates)
241→    .where(eq(oauthStates.state, state as string))
242→    .limit(1);
243→
244→  if (!oauthState || oauthState.expiresAt < new Date()) {
245→    return res.status(400).send('Invalid or expired state');
246→  }
247→
248→  // Clean up state
249→  await db.delete(oauthStates).where(eq(oauthStates.id, oauthState.id));
250→
251→  try {
252→    // Exchange code for tokens
253→    const tokenResponse = await axios.post(OAUTH_CONFIG.google.tokenUrl, {
254→      client_id: process.env.GOOGLE_CLIENT_ID,
255→      client_secret: process.env.GOOGLE_CLIENT_SECRET,
256→      code,
257→      grant_type: 'authorization_code',
258→      redirect_uri: `${process.env.BASE_URL}/auth/google/callback`
259→    });
260→
261→    const { access_token, refresh_token, expires_in } = tokenResponse.data;
262→
263→    // Get user info
264→    const userInfoResponse = await axios.get('https://www.googleapis.com/oauth2/v2/userinfo', {
265→      headers: { Authorization: `Bearer ${access_token}` }
266→    });
267→
268→    const { email, name } = userInfoResponse.data;
269→
270→    // Verify organization domain — change to your domain
271→    if (!email.endsWith('@example.com')) {
272→      return res.status(403).send('Only organization accounts are allowed');
273→    }
274→
275→    // Find or create user
276→    let [user] = await db
277→      .select()
278→      .from(users)
