282→    if (!user) {
283→      const [newUser] = await db
284→        .insert(users)
285→        .values({
286→          email,
287→          name,
288→          mcpToken: generateMcpToken()
289→        })
290→        .returning();
291→      user = newUser;
292→    }
293→
294→    // Upsert Google connection
295→    const [existingConnection] = await db
296→      .select()
297→      .from(connections)
298→      .where(
299→        and(
300→          eq(connections.userId, user.id),
301→          eq(connections.service, 'GOOGLE')
302→        )
303→      )
304→      .limit(1);
305→
306→    if (existingConnection) {
307→      await db
308→        .update(connections)
309→        .set({
310→          accessToken: encryptToken(access_token),
311→          refreshToken: refresh_token ? encryptToken(refresh_token) : null,
312→          expiresAt: new Date(Date.now() + expires_in * 1000),
313→          updatedAt: new Date()
314→        })
315→        .where(eq(connections.id, existingConnection.id));
316→    } else {
317→      await db.insert(connections).values({
318→        userId: user.id,
319→        service: 'GOOGLE',
320→        accessToken: encryptToken(access_token),
321→        refreshToken: refresh_token ? encryptToken(refresh_token) : null,
322→        expiresAt: new Date(Date.now() + expires_in * 1000)
323→      });
324→    }
325→
326→    // Set session
327→    req.session.userId = user.id;
328→
329→    res.redirect('/auth');
330→  } catch (error: unknown) {
331→    const message = error instanceof Error ? error.message : 'Unknown error';
332→    console.error('Google OAuth error:', message);
333→    res.status(500).send('Authentication failed');
334→  }
