  const service = req.params.service.toUpperCase() as Service;

  try {
    await db
      .delete(connections)
      .where(
        and(
          eq(connections.userId, userId),
          eq(connections.service, service)
        )
      );
  } catch {
    // Ignore if not found
  }

  res.redirect('/auth');
});

authRouter.get('/logout', (req: Request, res: Response) => {
  req.session.destroy(() => {
    res.redirect('/auth');
  });
});

