// ============================================================
// Task CRUD Operations
// ============================================================

taskRouter.post('/create', async (req: Request, res: Response) => {
  const userId = req.session?.userId;
  if (!userId) return res.status(401).send('Unauthorized');

  const { name, description, taskType, schedule, timezone, config, notifySlack, notifyEmail } = req.body;

  // Validate cron expression
  if (!cron.validate(schedule)) {
    return res.status(400).send('Invalid cron expression');
  }

  // Parse config JSON
  let parsedConfig = {};
  try {
    parsedConfig = config ? JSON.parse(config) : {};
  } catch {
    return res.status(400).send('Invalid JSON in configuration');
  }

  const [task] = await db
    .insert(scheduledTasks)
    .values({
      userId,
      name,
      description,
      taskType: taskType as TaskType,
      schedule,
      timezone: timezone || 'America/New_York',
      config: parsedConfig,
      notifySlack: notifySlack || null,
      notifyEmail: notifyEmail || null,
      enabled: true
    })
    .returning();

  // Schedule the task
  try {
    scheduleTask(task);
  } catch (e: unknown) {
    const message = e instanceof Error ? e.message : 'Unknown error';
    console.error('Failed to schedule task:', message);
  }

  res.redirect('/tasks');
});

taskRouter.post('/:id/toggle', async (req: Request, res: Response) => {
  const userId = req.session?.userId;
  if (!userId) return res.status(401).send('Unauthorized');

  const [task] = await db
    .select()
    .from(scheduledTasks)
    .where(
      and(
        eq(scheduledTasks.id, req.params.id),
        eq(scheduledTasks.userId, userId)
      )
    )
    .limit(1);

  if (!task) return res.status(404).send('Task not found');

  await db
    .update(scheduledTasks)
    .set({ enabled: !task.enabled, updatedAt: new Date() })
    .where(eq(scheduledTasks.id, task.id));

  await reloadTask(task.id);

  res.redirect('/tasks');
});

taskRouter.post('/:id/run', async (req: Request, res: Response) => {
  const userId = req.session?.userId;
  if (!userId) return res.status(401).send('Unauthorized');

  const [task] = await db
    .select()
    .from(scheduledTasks)
    .where(
      and(
        eq(scheduledTasks.id, req.params.id),
        eq(scheduledTasks.userId, userId)
      )
    )
    .limit(1);

  if (!task) return res.status(404).send('Task not found');

  // Run in background
  runTask(task.id).catch(e => console.error('Task run failed:', e));

  res.json({ success: true, message: 'Task started' });
});

taskRouter.post('/:id/delete', async (req: Request, res: Response) => {
  const userId = req.session?.userId;
  if (!userId) return res.status(401).send('Unauthorized');

  const [task] = await db
    .select()
    .from(scheduledTasks)
    .where(
      and(
        eq(scheduledTasks.id, req.params.id),
        eq(scheduledTasks.userId, userId)
      )
    )
    .limit(1);

  if (!task) return res.status(404).send('Task not found');

  unscheduleTask(task.id);

  await db
    .delete(scheduledTasks)
    .where(eq(scheduledTasks.id, task.id));

  res.redirect('/tasks');
});

taskRouter.get('/:id/edit', async (req: Request, res: Response) => {
  const userId = req.session?.userId;
